const root = $input.first().json;
const data = root.body ? root.body : root;
const args = data.input || data.arguments || data;

const perfil = String(args.perfil || '').toUpperCase();
const idade = parseInt(args.idade, 10);
const obstetricia = args.obstetricia === true || args.obstetricia === 'true';

if (!['PF', 'PJ'].includes(perfil) || isNaN(idade)) {
  throw new Error('Parâmetros inválidos: perfil (PF|PJ) e idade são obrigatórios.');
}

function faixaDe(i) {
  if (i <= 18) return '0-18';   // ATENÇÃO fronteira 17/18: confirme a regra de negócio
  if (i <= 23) return '19-23';
  if (i <= 28) return '24-28';
  if (i <= 33) return '29-33';
  if (i <= 38) return '34-38';
  if (i <= 43) return '39-43';
  if (i <= 48) return '44-48';
  if (i <= 53) return '49-53';
  if (i <= 58) return '54-58';
  return '59+';
}

