  for (const [produto, valor] of Object.entries(band)) {
    const linha = produto.indexOf('Vital') === 0 ? 'Vital' : 'Superior';
    const modalidade = produto.replace(/^Vital\s|^Superior\s/, '');
    planos.push({ linha, modalidade, valor_mensal: valor });
  }
  promocao_adesao = 'PJ/MEI: 30% de desconto nas 6 primeiras mensalidades + isenção de coparticipação (4 meses nas linhas Vital; toda a vigência na linha Superior).';
} else {
  const menor = idade < 18;
  const vitalKey = (menor || !obstetricia) ? 'pf_vital_sem_obstetricia' : 'pf_vital_com_obstetricia';
  tabela_usada = vitalKey + ' + pf_superior';
  const vital = (PRICING.pricing_tables[vitalKey] || {})[faixa] || {};
  for (const [modalidade, v] of Object.entries(vital)) {
    planos.push({ linha: 'Vital', modalidade, valor_mensal: v.full });
  }
  const sup = (PRICING.pricing_tables.pf_superior || {})[faixa] || {};
  for (const [modalidade, v] of Object.entries(sup)) {
    planos.push({ linha: 'Superior', modalidade, valor_mensal: v.full });
  }
  promocao_adesao = 'Copay Completa: 100% off na 1ª mensalidade e 50% na 2ª. Copay Básica: 20% nas 4 primeiras. Depois, valor cheio.';
}

return [{ json: { perfil, idade, faixa_etaria: faixa, tabela_usada, planos, promocao_adesao } }];
